 1	import { type FC, useMemo } from 'react';
 2	import { loadUserSettings } from 'src/components/common/Page/userSettings';
 3	import type { RowProps } from 'src/components/common/TableView/types';
 4	import { StandardPageWithSelection } from 'src/components/page/StandardPageWithSelection';
 5	import type { ProviderData } from 'src/modules/Providers/utils/types/ProviderData';
 6	import { useForkliftTranslation } from 'src/utils/i18n';
 7	
 8	import type { ResourceField } from '@components/common/utils/types';
 9	import { EmptyState, EmptyStateVariant, Spinner, Title } from '@patternfly/react-core';
10	import { getNamespace } from '@utils/crds/common/selectors';
11	
12	import { getVmId } from '../utils/helpers/vmProps';
13	
14	import { ConcernsTable } from './ConcernsTable';
15	import { extraSupportedFilters, extraSupportedMatchers } from './constants';
16	import type { VmData } from './VMCellProps';
17	
18	type ProviderVirtualMachinesListProps = {
19	  title?: string;
20	  obj: ProviderData;
21	  ns?: string;
22	  loaded?: boolean;
23	  loadError?: unknown;
24	  cellMapper: FC<RowProps<VmData>>;
25	  fieldsMetadata: ResourceField[];
26	  pageId: string;
27	  onSelect?: (selectedVMs: VmData[] | undefined) => void;
28	  initialSelectedIds?: string[];
29	  showActions: boolean;
30	  className?: string;
31	};
32	
33	export const ProviderVirtualMachinesList: FC<ProviderVirtualMachinesListProps> = ({
34	  cellMapper,
35	  className,
36	  fieldsMetadata,
37	  initialSelectedIds = [],
38	  obj,
39	  onSelect,
40	  pageId,
41	  title,
42	}) => {
43	  const { t } = useForkliftTranslation();
44	  const { vmData, vmDataLoading } = obj;
45	  const provider = obj?.provider;
46	  const namespace = (provider ? getNamespace(provider) : '') ?? '';
47	
48	  const userSettings = useMemo(() => loadUserSettings({ pageId }), [pageId]);
49	
50	  const handleSelectedIds = onSelect
51	    ? (selectedIds: string[]) => {
52	        const selectedVms = vmData?.filter((data) => selectedIds.includes(getVmId(data)));
53	        onSelect(selectedVms);
54	      }
55	    : undefined;
56	
57	  // Render the spinner while data is loading
58	  if (vmDataLoading) {
59	    return (
60	      <EmptyState variant={EmptyStateVariant.sm}>
61	        <Spinner size="xl" />
62	        <Title headingLevel="h4" size="lg">
63	          {t('Loading virtual machines...')}
64	        </Title>
65	      </EmptyState>
66	    );
67	  }
68	
69	  return (
70	    <StandardPageWithSelection
71	      className={className}
72	      data-testid="vm-list"
73	      dataSource={[vmData ?? [], !vmDataLoading, null]}
74	      CellMapper={cellMapper}
75	      fieldsMetadata={fieldsMetadata}
76	      namespace={namespace}
77	      title={title ?? t('Virtual machines')}
78	      userSettings={userSettings}
79	      extraSupportedFilters={extraSupportedFilters}
80	      extraSupportedMatchers={extraSupportedMatchers}
81	      toId={getVmId}
82	      onSelect={handleSelectedIds}
83	      selectedIds={initialSelectedIds}
84	      page={1}
85	      expandedIds={[]}
86	      ExpandedComponent={(props) => <ConcernsTable {...props} />}
87	    />
88	  );
89	};

